338→export const computeStarPullOffsets = (
339→    starPulls,
340→    galaxyTargets,
341→    starBases,
342→    pullStrength = 120,
343→    maxOffset = 80
344→) => {
345→    const offsets = new Map();
346→    if (!Array.isArray(starPulls) || starPulls.length === 0) return offsets;
347→    if (!(galaxyTargets instanceof Map) || !(starBases instanceof Map)) return offsets;
348→
349→    const resolvedPullStrength = Number.isFinite(Number(pullStrength)) ? Number(pullStrength) : 120;
350→
351→    for (const pull of starPulls) {
352→        const postId = pull?.post_id;
353→        const galaxyId = pull?.galaxy_user_id;
354→        const similarity = Number(pull?.similarity);
355→        if (!postId || !galaxyId || !Number.isFinite(similarity) || similarity <= 0.4) continue;
356→
357→        const galaxy = galaxyTargets.get(galaxyId);
358→        const base = starBases.get(postId);
359→        if (!galaxy || !base) continue;
360→
361→        const dx = galaxy.x - base.x;
362→        const dy = galaxy.y - base.y;
363→        const dist = Math.sqrt(dx * dx + dy * dy) || 1;
364→
365→        const strength = (similarity - 0.4) * resolvedPullStrength;
366→        const fx = (dx / dist) * strength;
367→        const fy = (dy / dist) * strength;
368→
369→        if (!offsets.has(postId)) {
370→            offsets.set(postId, { dx: 0, dy: 0 });
371→        }
372→        const offset = offsets.get(postId);
373→        offset.dx += fx;
374→        offset.dy += fy;
375→    }
376→
377→    for (const [postId, offset] of offsets.entries()) {
378→        offsets.set(postId, clampOffsetMagnitude(offset, maxOffset));
379→    }
380→
381→    return offsets;
382→};
383→
384→export const computeStarPullOffsetsFromEmbeddings = ({
385→    posts = [],
386→    galaxyCentroids = new Map(),
387→    galaxyPositions = new Map(),
388→    activePostIds = null,
389→    activeGalaxyIds = null,
390→    minSimilarity = 0.4,
391→    pullStrength = 120,
392→    maxOffset = 80,
393→    maxGalaxyLinks = 6,
394→} = {}) => {
395→    const offsets = new Map();
396→    if (!Array.isArray(posts) || posts.length === 0) return offsets;
397→    if (!(galaxyCentroids instanceof Map) || galaxyCentroids.size === 0) return offsets;
398→    if (!(galaxyPositions instanceof Map) || galaxyPositions.size === 0) return offsets;
399→
400→    const minSim = Number.isFinite(Number(minSimilarity)) ? Number(minSimilarity) : 0.4;
401→    const resolvedPullStrength = Number.isFinite(Number(pullStrength)) ? Number(pullStrength) : 120;
402→    const topGalaxyLimit = normalizeMaxEdges(maxGalaxyLinks, 6);
403→
404→    const galaxyIds = activeGalaxyIds
405→        ? Array.from(activeGalaxyIds).filter((id) => galaxyCentroids.has(id) && galaxyPositions.has(id))
406→        : Array.from(galaxyCentroids.keys()).filter((id) => galaxyPositions.has(id));
407→
408→    if (galaxyIds.length === 0) return offsets;
409→
410→    for (const post of posts) {
411→        const postId = post?.id;
412→        if (!postId) continue;
413→        if (activePostIds && !activePostIds.has(postId)) continue;
414→
415→        const ownerId = post?.users?.id ?? post?.user_id;
416→        const postEmbedding = normalizeEmbedding(post?.embeddings);
417→        if (!postEmbedding) continue;
418→
419→        const baseX = toFiniteNumber(post?.universe_x) ?? toFiniteNumber(post?.display_x);
420→        const baseY = toFiniteNumber(post?.universe_y) ?? toFiniteNumber(post?.display_y);
421→        if (baseX == null || baseY == null) continue;
422→
423→        const candidates = [];
424→        for (const galaxyId of galaxyIds) {
425→            if (!galaxyId || galaxyId === ownerId) continue;
426→
427→            const centroidEmbedding = galaxyCentroids.get(galaxyId);
428→            const galaxyPos = galaxyPositions.get(galaxyId);
429→            if (!centroidEmbedding || !galaxyPos) continue;
430→
431→            const sim = cosineSimilarity(postEmbedding, centroidEmbedding);
432→            if (sim < minSim) continue;
433→
434→            candidates.push({ sim, galaxyPos });
435→        }
436→
437→        if (candidates.length === 0) continue;
438→        candidates.sort((a, b) => b.sim - a.sim);
439→
440→        let dxSum = 0;
441→        let dySum = 0;
442→        const limit = Math.min(candidates.length, topGalaxyLimit);
443→        for (let i = 0; i < limit; i++) {
444→            const { sim, galaxyPos } = candidates[i];
445→            const dx = galaxyPos.x - baseX;
446→            const dy = galaxyPos.y - baseY;
447→            const dist = Math.sqrt(dx * dx + dy * dy) || 1;
448→            const strength = (sim - minSim) * resolvedPullStrength;
449→            dxSum += (dx / dist) * strength;
450→            dySum += (dy / dist) * strength;
451→        }
452→
453→        offsets.set(postId, clampOffsetMagnitude({ dx: dxSum, dy: dySum }, maxOffset));
454→    }
455→
456→    return offsets;
457→};
458→
459→export const computeSemanticBridges = (
460→    posts,
461→    computedStarPositions,
462→    threshold = 0.9,
463→    maxPairs = 120
464→) => {
465→    if (!Array.isArray(posts) || posts.length < 2) return [];
466→    if (!(computedStarPositions instanceof Map)) return [];
467→
468→    const minSimilarity = Number.isFinite(Number(threshold)) ? Number(threshold) : 0.9;
469→    const limit = normalizeMaxEdges(maxPairs, 120);
470→
471→    const enriched = [];
472→    for (const post of posts) {
473→        const postId = post?.id;
474→        if (!postId || !computedStarPositions.has(postId)) continue;
475→        const embedding = normalizeEmbedding(post?.embeddings);
476→        if (!embedding) continue;
477→        enriched.push({ postId, embedding });
478→    }
479→
480→    if (enriched.length < 2) return [];
481→
482→    const pairs = [];
483→    for (let i = 0; i < enriched.length; i++) {
484→        for (let j = i + 1; j < enriched.length; j++) {
485→            const similarity = cosineSimilarity(enriched[i].embedding, enriched[j].embedding);
486→            if (similarity > minSimilarity) {
487→                pairs.push({
488→                    post_a: enriched[i].postId,
489→                    post_b: enriched[j].postId,
490→                    similarity,
491→                });
492→            }
493→        }
494→    }
495→
496→    pairs.sort((a, b) => b.similarity - a.similarity);
497→    return pairs.length > limit ? pairs.slice(0, limit) : pairs;
498→};
