  1→import React, { useRef, useEffect } from 'react';
  2→import { Group, Circle, Text } from 'react-konva';
  3→import Konva from 'konva';
  4→import { hexToRgba } from '../utils/starUtils';
  5→
  6→const StarGroup = React.memo(({ x, y, radius, color, title, showTitle, isPulsing, onClick, onPointerDown }) => {
  7→    const r = radius;
  8→    const groupRef = useRef(null);
  9→    const tweenRef = useRef(null);
 10→
 11→    useEffect(() => {
 12→        const node = groupRef.current;
 13→        if (!node) return;
 14→
 15→        // Cleanup any running tween
 16→        if (tweenRef.current) {
 17→            tweenRef.current.destroy();
 18→            tweenRef.current = null;
 19→        }
 20→
 21→        if (isPulsing) {
 22→            // Phase 1: elastic scale up 1 → 1.8
 23→            const tweenUp = new Konva.Tween({
 24→                node,
 25→                scaleX: 1.8,
 26→                scaleY: 1.8,
 27→                duration: 0.35,
 28→                easing: Konva.Easings.ElasticEaseOut,
 29→                onFinish: () => {
 30→                    // Phase 2: ease back down 1.8 → 1
 31→                    const tweenDown = new Konva.Tween({
 32→                        node,
 33→                        scaleX: 1,
 34→                        scaleY: 1,
 35→                        duration: 0.25,
 36→                        easing: Konva.Easings.EaseOut,
 37→                    });
 38→                    tweenRef.current = tweenDown;
 39→                    tweenDown.play();
 40→                },
 41→            });
 42→            tweenRef.current = tweenUp;
 43→            tweenUp.play();
 44→        } else {
 45→            // Reset to default scale
 46→            node.scaleX(1);
 47→            node.scaleY(1);
 48→        }
 49→
 50→        return () => {
 51→            if (tweenRef.current) {
 52→                tweenRef.current.destroy();
 53→                tweenRef.current = null;
 54→            }
 55→        };
 56→    }, [isPulsing]);
 57→
 58→    return (
 59→        <Group
 60→            ref={groupRef}
 61→            x={x}
 62→            y={y}
 63→        >
 64→            {/* Outer atmosphere — shadow glow */}
 65→            <Circle
 66→                radius={r * 3}
 67→                fill="transparent"
 68→                shadowColor={color}
 69→                shadowBlur={r * 5}
 70→                shadowOpacity={1}
 71→                perfectDrawEnabled={false}
 72→                shadowForStrokeEnabled={false}
 73→                listening={false}
 74→            />
 75→            {/* Inner glow — radial gradient */}
 76→            <Circle
 77→                radius={r * 2.2}
 78→                fillRadialGradientStartPoint={{ x: 0, y: 0 }}
 79→                fillRadialGradientEndPoint={{ x: 0, y: 0 }}
 80→                fillRadialGradientStartRadius={0}
 81→                fillRadialGradientEndRadius={r * 2.2}
 82→                fillRadialGradientColorStops={[
 83→                    0, color,
 84→                    0.4, hexToRgba(color, 0.65),
 85→                    1, hexToRgba(color, 0),
 86→                ]}
 87→                perfectDrawEnabled={false}
 88→                listening={false}
 89→            />
 90→            {/* Bright core */}
 91→            <Circle
 92→                radius={r * 0.5}
 93→                fill="#ffffffee"
 94→                shadowColor="#ffffff"
 95→                shadowBlur={4}
 96→                shadowOpacity={1}
 97→                perfectDrawEnabled={false}
 98→                hitStrokeWidth={r + 12}
 99→                onClick={onClick}
100→                onTap={onClick}
101→                onMouseDown={onPointerDown ? (e) => {
102→                    e.cancelBubble = true;
103→                    const screenX = e.evt.clientX;
104→                    const screenY = e.evt.clientY;
105→                    onPointerDown(screenX, screenY);
106→                } : undefined}
107→                onTouchStart={onPointerDown ? (e) => {
108→                    e.cancelBubble = true;
109→                    const touch = e.evt.touches?.[0];
110→                    if (touch) onPointerDown(touch.clientX, touch.clientY);
111→                } : undefined}
112→            />
113→            {showTitle && title && (
114→                <Text
115→                    text={title.length > 24 ? title.slice(0, 22) + '...' : title}
116→                    y={r * 2.2 + 4}
117→                    fontSize={10}
118→                    fill="rgba(255,255,255,0.6)"
119→                    align="center"
120→                    width={120}
121→                    offsetX={60}
122→                    listening={false}
123→                    perfectDrawEnabled={false}
124→                />
125→            )}
126→        </Group>
127→    );
128→});
129→
130→StarGroup.displayName = 'StarGroup';
131→
132→export default StarGroup;
